// Build status update message for WhatsApp
const data = $input.first().json.body;

const statusConfig = {
  confirmed: {
    emoji: '✅',
    title: 'Order Confirmed',
    body: 'Your order has been confirmed and will be prepared shortly!'
  },
  preparing: {
    emoji: '👨‍🍳',
    title: 'Being Prepared',
    body: 'Our chef is preparing your delicious food!'
  },
  ready: {
    emoji: '📦',
    title: 'Ready for Pickup/Delivery',
    body: 'Your order is ready and will be dispatched soon!'
  },
  out_for_delivery: {
    emoji: '🚗',
    title: 'Out for Delivery',
    body: 'Your order is on the way! Get ready!'
  },
  delivered: {
    emoji: '🎉',
    title: 'Delivered',
    body: 'Your order has been delivered! Enjoy your meal!\n\nThank you for ordering with us! 🙏'
  },
  cancelled: {
    emoji: '❌',
    title: 'Order Cancelled',
    body: `Your order has been cancelled.${data.rejection_reason ? '\nReason: ' + data.rejection_reason : ''}\n\nIf you have questions, please contact us.`
  }
};

const status = statusConfig[data.new_status] || {
  emoji: '📋',
  title: data.new_status?.replace(/_/g, ' ').toUpperCase() || 'Updated',
  body: 'Your order status has been updated.'
};

let message = `${status.emoji} *${status.title}*\n\n`;
message += `🆔 Order #${data.order_id?.substring(0, 8)}\n`;
message += `${status.body}`;

if (data.estimated_delivery_time) {
  const eta = new Date(data.estimated_delivery_time);
  message += `\n\n⏰ Estimated delivery: ${eta.toLocaleTimeString('en-PK', { hour: '2-digit', minute: '2-digit' })}`;
}

return [{
  json: {
    to: data.customer_phone,
    message: message,
    order_id: data.order_id,
    new_status: data.new_status
  }
}];

// Send feedback request after delivery
const data = $input.first().json;

return [{
  json: {
    to: data.to,
    message: `⭐ *How was your experience?*

We'd love your feedback!

Rate us (1-5 stars):
1️⃣ ⭐
2️⃣ ⭐⭐
3️⃣ ⭐⭐⭐
4️⃣ ⭐⭐⭐⭐
5️⃣ ⭐⭐⭐⭐⭐

Reply with a number (1-5)`
  }
}];
